 11→import { TeamBoard } from "./components/TeamBoard";
 12→import { DebugViewer } from "./components/DebugViewer";
 13→import { InfoBar } from "./components/InfoBar";
 14→import { KeybindBar } from "./components/KeybindBar";
 15→import { ViewToolbar } from "./components/ViewToolbar";
 16→import { ProjectTree, useProjectKeys } from "./components/ProjectTree";
 17→import { ResizeHandle } from "./components/ResizeHandle";
 18→import { SettingsModal } from "./components/SettingsModal";
 19→
 20→export function App() {
 21→  const [view, setView] = useState<ViewState>("picker");
 22→  const [selectedMessage, setSelectedMessage] = useState(0);
 23→  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 24→  const [showKeybinds, setShowKeybinds] = useState(true);
 25→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 26→  const [sidebarWidth, setSidebarWidth] = useState(180);
 27→  const [sidebarFocused, setSidebarFocused] = useState(false);
 28→  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 29→  const [showSettings, setShowSettings] = useState(false);
 30→
 31→  const handleSelectProject = useCallback(
 32→    (project: string | null) => {
 33→      setSelectedProject(project);
 34→      setPickerSelectedIndex(0);
 35→      setSidebarFocused(false);
 36→      if (view !== "picker") setView("picker");
 37→    },
 38→    [view],
 39→  );
 40→
 41→  const session = useSession();
 42→  const picker = usePicker(selectedProject);
 43→  const projectKeys = useProjectKeys(picker.allSessions);
 44→
 45→  const { loadSession, loadDebugLog, sessionPath } = session;
 46→  const { discoverSessions } = picker;
 47→
 48→  const {
 49→    set: expandedMessages,
 50→    toggle: toggleMessage,
 51→    clear: clearExpanded,
 52→    addAll: expandMessages,
 53→  } = useToggleSet();
 54→
 55→  // Shared: fetch project dirs and discover sessions
 56→  const loadProjectDirs = useCallback(async () => {
 57→    try {
 58→      const dirs = await invoke<string[]>("get_project_dirs");
 59→      if (dirs.length > 0) {
 60→        discoverSessions(dirs);
 61→      }
 62→    } catch (err) {
 63→      console.error("Failed to get project dirs:", err);
 64→    }
 65→  }, [discoverSessions]);
 66→
 67→  // Auto-discover sessions on mount; show settings if no path configured
 68→  const discoveredRef = useRef(false);
 69→  useEffect(() => {
 70→    if (discoveredRef.current) return;
 71→    discoveredRef.current = true;
 72→    const discover = async () => {
 73→      let hasConfig = false;
 74→      try {
 75→        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
 76→        hasConfig = settings.projects_dir != null;
 77→      } catch {
 78→        // no settings file yet
 79→      }
 80→      if (!hasConfig) {
 81→        setShowSettings(true);
 82→        return;
 83→      }
 84→      loadProjectDirs();
 85→    };
 86→    discover();
 87→  }, [loadProjectDirs]);
 88→
 89→  // Handle session selection from picker
 90→  const handleSelectSession = useCallback(
 91→    (sessionInfo: SessionInfo) => {
 92→      loadSession(sessionInfo.path);
 93→      setView("list");
 94→      setSelectedMessage(0);
 95→      clearExpanded();
 96→    },
 97→    [loadSession, clearExpanded],
 98→  );
 99→
100→  // Auto-select newest message (last index) when messages load
101→  useEffect(() => {
102→    if (session.messages.length > 0 && view === "list") {
103→      setSelectedMessage((prev) =>
104→        prev >= session.messages.length ? session.messages.length - 1 : prev,
105→      );
106→    }
107→  }, [session.messages.length, view]);
108→
109→  // Open detail view
110→  const openDetail = useCallback((index: number) => {
111→    setSelectedMessage(index);
112→    setView("detail");
113→  }, []);
114→
115→  // -- Extracted action callbacks for toolbar + keyboard --
116→
117→  const expandAll = useCallback(() => {
118→    const claudeIndices: number[] = [];
119→    session.messages.forEach((msg, i) => {
120→      if (msg.role === "claude") claudeIndices.push(i);
121→    });
122→    expandMessages(claudeIndices);
123→  }, [session.messages, expandMessages]);
124→
125→  const collapseAll = useCallback(() => {
126→    clearExpanded();
127→  }, [clearExpanded]);
128→
129→  // Visual top = newest message = last index (display is reversed)
130→  const jumpToTop = useCallback(() => {
131→    setSelectedMessage(Math.max(session.messages.length - 1, 0));
132→  }, [session.messages.length]);
133→
134→  // Visual bottom = oldest message = index 0
135→  const jumpToBottom = useCallback(() => {
136→    setSelectedMessage(0);
137→  }, []);
138→
139→  const openDebug = useCallback(() => {
140→    if (sessionPath) {
141→      loadDebugLog(sessionPath);
142→      setView("debug");
143→    }
144→  }, [sessionPath, loadDebugLog]);
145→
146→  const openTeams = useCallback(() => {
147→    if (session.teams.length > 0) setView("team");
148→  }, [session.teams.length]);
149→
150→  const goToSessions = useCallback(() => {
151→    setView("picker");
152→  }, []);
153→
154→  const backToList = useCallback(() => {
155→    if (sessionPath) setView("list");
156→  }, [sessionPath]);
157→
158→  const toggleKeybinds = useCallback(() => {
159→    setShowKeybinds((v) => !v);
160→  }, []);
161→
162→  const selectProjectByIndex = useCallback(
163→    (index: number) => {
164→      if (index >= 0 && index < projectKeys.length) {
165→        handleSelectProject(projectKeys[index]);
166→      }
167→    },
168→    [projectKeys, handleSelectProject],
169→  );
170→
171→  // Keyboard navigation — build keyMap per view
172→  const keyMap: Record<string, () => void> = {};
173→
174→  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
175→  if (sidebarFocused) {
176→    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
177→    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
178→    keyMap["j"] = sidebarDown;
179→    keyMap["ArrowDown"] = sidebarDown;
180→    keyMap["k"] = sidebarUp;
181→    keyMap["ArrowUp"] = sidebarUp;
182→    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
183→    keyMap["Escape"] = () => setSidebarFocused(false);
184→    keyMap["l"] = () => setSidebarFocused(false);
185→    keyMap["ArrowRight"] = () => setSidebarFocused(false);
186→    keyMap["?"] = toggleKeybinds;
187→  } else {
188→    switch (view) {
189→      case "list": {
190→        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
191→        const listUp = () =>
192→          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
193→        keyMap["j"] = listDown;
194→        keyMap["ArrowDown"] = listDown;
195→        keyMap["k"] = listUp;
196→        keyMap["ArrowUp"] = listUp;
197→        keyMap["G"] = jumpToTop;
198→        keyMap["g"] = jumpToBottom;
199→        keyMap["Tab"] = () => toggleMessage(selectedMessage);
200→        keyMap["Enter"] = () => {
201→          if (session.messages.length > 0) openDetail(selectedMessage);
202→        };
203→        keyMap["e"] = expandAll;
204→        keyMap["c"] = collapseAll;
205→        keyMap["t"] = openTeams;
206→        keyMap["d"] = openDebug;
207→        keyMap["q"] = goToSessions;
208→        keyMap["Escape"] = goToSessions;
209→        keyMap["s"] = goToSessions;
210→        keyMap["?"] = toggleKeybinds;
211→        keyMap["h"] = () => setSidebarFocused(true);
212→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
213→        break;
214→      }
215→      case "detail":
216→        // j/k/Tab/Enter/q/Escape handled by MessageDetail's own useKeyboard
217→        keyMap["?"] = toggleKeybinds;
218→        break;
219→      case "picker": {
220→        const pickerDown = () =>
221→          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
222→        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
223→        keyMap["j"] = pickerDown;
224→        keyMap["ArrowDown"] = pickerDown;
225→        keyMap["k"] = pickerUp;
226→        keyMap["ArrowUp"] = pickerUp;
227→        keyMap["Enter"] = () => {
228→          if (picker.sessions[pickerSelectedIndex])
229→            handleSelectSession(picker.sessions[pickerSelectedIndex]);
230→        };
231→        keyMap["q"] = backToList;
232→        keyMap["Escape"] = backToList;
233→        keyMap["?"] = toggleKeybinds;
234→        keyMap["h"] = () => setSidebarFocused(true);
235→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
236→        break;
237→      }
238→      case "team":
239→        keyMap["q"] = () => setView("list");
240→        keyMap["Escape"] = () => setView("list");
241→        keyMap["?"] = toggleKeybinds;
242→        break;
243→      case "debug":
244→        keyMap["q"] = () => setView("list");
245→        keyMap["Escape"] = () => setView("list");
246→        keyMap["?"] = toggleKeybinds;
247→        break;
248→    }
249→  }
250→  useKeyboard(keyMap);
251→
252→  // Keybind bar click actions
253→  const keybindActions: Record<string, () => void> = {};
254→  if (view === "list") {
255→    keybindActions["debug"] = openDebug;
256→    keybindActions["sessions"] = goToSessions;
257→    if (session.teams.length > 0) {
258→      keybindActions["tasks"] = openTeams;
259→    }
260→  } else if (view === "picker") {
261→    keybindActions["back"] = backToList;
262→  } else if (view === "detail") {
263→    keybindActions["back"] = () => setView("list");
264→  } else if (view === "team") {
265→    keybindActions["back"] = () => setView("list");
266→  } else if (view === "debug") {
267→    keybindActions["back"] = () => setView("list");
268→  }
269→
270→  // Render the active view
271→  const renderView = () => {
272→    switch (view) {
273→      case "picker":
274→        return (
275→          <SessionPicker
276→            sessions={picker.sessions}
277→            loading={picker.loading}
278→            searchQuery={picker.searchQuery}
279→            selectedIndex={pickerSelectedIndex}
280→            onSelect={handleSelectSession}
281→            onSearchChange={picker.setSearchQuery}
282→            onSelectIndex={setPickerSelectedIndex}
283→          />
284→        );
285→
286→      case "list":
287→        return (
288→          <MessageList
289→            messages={session.messages}
290→            selectedIndex={selectedMessage}
291→            expandedSet={expandedMessages}
292→            ongoing={session.ongoing}
293→            onSelect={setSelectedMessage}
294→            onToggle={toggleMessage}
295→            onOpenDetail={openDetail}
296→          />
297→        );
298→
299→      case "detail":
300→        if (session.messages.length > 0 && selectedMessage < session.messages.length) {
301→          return (
302→            <MessageDetail
303→              message={session.messages[selectedMessage]}
304→              ongoing={session.ongoing}
305→              onBack={() => setView("list")}
306→            />
307→          );
308→        }
309→        return null;
310→
311→      case "team":
312→        return <TeamBoard teams={session.teams} onBack={() => setView("list")} />;
313→
314→      case "debug":
315→        return <DebugViewer entries={session.debugEntries} onBack={() => setView("list")} />;
316→    }
317→  };
318→
319→  return (
320→    <div className="app">
321→      {/* Info bar — only show when we have a loaded session */}
322→      {session.sessionPath && view !== "picker" && (
323→        <InfoBar
324→          meta={session.meta}
325→          gitInfo={session.gitInfo}
326→          messages={session.messages}
327→          sessionTotals={session.sessionTotals}
328→          sessionPath={session.sessionPath}
329→          ongoing={session.ongoing}
330→        />
331→      )}
332→
333→      {/* View toolbar */}
334→      <ViewToolbar
335→        view={view}
336→        hasTeams={session.teams.length > 0}
337→        hasSession={!!session.sessionPath}
338→        messageCount={session.messages.length}
339→        onGoToSessions={goToSessions}
340→        onExpandAll={expandAll}
341→        onCollapseAll={collapseAll}
342→        onJumpTop={jumpToTop}
343→        onJumpBottom={jumpToBottom}
344→        onOpenTeams={openTeams}
345→        onOpenDebug={openDebug}
346→        onBackToList={backToList}
347→        onOpenSettings={() => setShowSettings(true)}
348→      />
349→
350→      <div className="app-body">
351→        <ProjectTree
352→          sessions={picker.allSessions}
353→          selectedProject={selectedProject}
354→          highlightedIndex={sidebarHighlight}
355→          isFocused={sidebarFocused}
356→          onSelectProject={handleSelectProject}
357→          onRefresh={loadProjectDirs}
358→          onFocus={() => setSidebarFocused(true)}
359→          refreshing={picker.loading}
360→          style={{ width: sidebarWidth, minWidth: 100, maxWidth: 400 }}
361→        />
362→        <ResizeHandle onResize={setSidebarWidth} />
363→        <div className="main-content" onClick={() => setSidebarFocused(false)}>
364→          {renderView()}
365→        </div>
366→      </div>
367→
368→      {/* Keybind bar */}
369→      <KeybindBar
370→        view={view}
371→        hasTeams={session.teams.length > 0}
372→        showHints={showKeybinds}
373→        onToggle={toggleKeybinds}
374→        actions={keybindActions}
375→      />
376→
377→      {showSettings && (
378→        <SettingsModal onClose={() => setShowSettings(false)} onSaved={loadProjectDirs} />
379→      )}
380→    </div>
381→  );
382→}
