 1→import { useState, useEffect, useCallback } from "react";
 2→import { invoke } from "@tauri-apps/api/core";
 3→import type { SessionInfo } from "../types";
 4→import { useTauriEvent } from "./useTauriEvent";
 5→
 6→interface PickerState {
 7→  sessions: SessionInfo[];
 8→  loading: boolean;
 9→  searchQuery: string;
10→}
11→
12→export function usePicker(selectedProject: string | null = null) {
13→  const [state, setState] = useState<PickerState>({
14→    sessions: [],
15→    loading: false,
16→    searchQuery: "",
17→  });
18→
19→  const discoverSessions = useCallback(async (projectDirs: string[]) => {
20→    setState((prev) => ({ ...prev, loading: true }));
21→    try {
22→      const sessions = await invoke<SessionInfo[]>("discover_sessions", {
23→        projectDirs,
24→      });
25→      setState((prev) => ({ ...prev, sessions, loading: false }));
26→
27→      // Start watching for new sessions
28→      try {
29→        await invoke<void>("watch_picker", { projectDirs });
30→      } catch {
31→        // watcher is optional
32→      }
33→    } catch (err) {
34→      console.error("Failed to discover sessions:", err);
35→      setState((prev) => ({ ...prev, loading: false }));
36→    }
37→  }, []);
38→
39→  const setSearchQuery = useCallback((query: string) => {
40→    setState((prev) => ({ ...prev, searchQuery: query }));
41→  }, []);
42→
43→  // Listen for picker-refresh events (backend already applies staleness)
44→  useTauriEvent<{ sessions: SessionInfo[] }>("picker-refresh", (payload) => {
45→    setState((prev) => ({
46→      ...prev,
47→      sessions: payload.sessions,
48→    }));
49→  });
50→
51→  // Cleanup on unmount
52→  useEffect(() => {
53→    return () => {
54→      invoke<void>("unwatch_picker").catch(() => {});
55→    };
56→  }, []);
57→
58→  // Filter sessions by search query
59→  let filteredSessions = state.searchQuery
60→    ? state.sessions.filter(
61→        (s) =>
62→          s.first_message.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
63→          s.session_id.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
64→          s.model.toLowerCase().includes(state.searchQuery.toLowerCase()),
65→      )
66→    : state.sessions;
67→
68→  // Filter by selected project
69→  if (selectedProject) {
70→    filteredSessions = filteredSessions.filter((s) =>
71→      s.path.replace(/\\/g, "/").includes(`/.claude/projects/${selectedProject}/`),
72→    );
73→  }
74→
75→  return {
76→    sessions: filteredSessions,
77→    allSessions: state.sessions,
78→    loading: state.loading,
79→    searchQuery: state.searchQuery,
80→    setSearchQuery,
81→    discoverSessions,
82→  };
83→}
