 1→import { useEffect, useRef } from "react";
 2→import { listen, type UnlistenFn } from "@tauri-apps/api/event";
 3→
 4→/**
 5→ * Subscribe to a Tauri event with automatic setup/teardown and cancellation safety.
 6→ * The handler is kept in a ref so it always sees fresh closures without re-subscribing.
 7→ */
 8→export function useTauriEvent<T>(event: string, handler: (payload: T) => void) {
 9→  const handlerRef = useRef(handler);
10→  handlerRef.current = handler;
11→
12→  const unlistenRef = useRef<UnlistenFn | null>(null);
13→
14→  useEffect(() => {
15→    let cancelled = false;
16→
17→    const setupListener = async () => {
18→      const unlisten = await listen<T>(event, (e) => {
19→        if (!cancelled) handlerRef.current(e.payload);
20→      });
21→
22→      if (!cancelled) {
23→        unlistenRef.current = unlisten;
24→      } else {
25→        unlisten();
26→      }
27→    };
28→
29→    setupListener();
30→
31→    return () => {
32→      cancelled = true;
33→      unlistenRef.current?.();
34→      unlistenRef.current = null;
35→    };
36→  }, [event]);
37→}
