 61→
 62→  it("calls set_projects_dir with null on reset", async () => {
 63→    mockInvoke.mockImplementation((cmd: string) => {
 64→      if (cmd === "get_settings")
 65→        return Promise.resolve({ projects_dir: "/custom/path", default_dir: DEFAULT_DIR });
