 1→use serde::Serialize;
 2→use tauri::State;
 3→
 4→use crate::state::AppState;
 5→
 6→/// Response for the frontend — always includes both the configured and default paths.
 7→#[derive(Serialize)]
 8→pub struct SettingsResponse {
 9→    /// The user-configured path, or null if using the default.
10→    pub projects_dir: Option<String>,
11→    /// The platform default path (e.g. ~/.claude/projects). Always present.
12→    pub default_dir: String,
13→}
14→
15→fn platform_default_dir() -> String {
16→    dirs::home_dir()
17→        .map(|h| {
18→            h.join(".claude")
19→                .join("projects")
20→                .to_string_lossy()
21→                .to_string()
22→        })
23→        .unwrap_or_default()
24→}
25→
26→fn build_response(settings: &crate::settings::Settings) -> SettingsResponse {
27→    SettingsResponse {
28→        projects_dir: settings.projects_dir.clone(),
29→        default_dir: platform_default_dir(),
30→    }
31→}
32→
33→#[tauri::command]
34→pub async fn get_settings(state: State<'_, AppState>) -> Result<SettingsResponse, String> {
35→    let guard = state.settings.lock().map_err(|e| e.to_string())?;
36→    Ok(build_response(&guard))
37→}
38→
39→#[tauri::command]
40→pub async fn set_projects_dir(
41→    path: Option<String>,
42→    state: State<'_, AppState>,
43→) -> Result<SettingsResponse, String> {
44→    if let Some(ref p) = path {
45→        let pb = std::path::PathBuf::from(p);
46→        if !pb.exists() {
47→            return Err(format!("path does not exist: {p}"));
48→        }
49→        if !pb.is_dir() {
50→            return Err(format!("path is not a directory: {p}"));
51→        }
52→    }
53→
54→    let mut guard = state.settings.lock().map_err(|e| e.to_string())?;
55→    guard.projects_dir = path;
56→    crate::settings::save_settings(&guard)?;
57→    Ok(build_response(&guard))
58→}
