 7→/// Discover sessions across project directories.
 8→/// Uses the session cache for efficient rescanning.
 9→/// Returns a flat array of SessionInfo sorted by mod_time descending.
10→#[tauri::command]
11→pub async fn discover_sessions(
12→    project_dirs: Vec<String>,
13→    state: State<'_, AppState>,
14→) -> Result<Vec<SessionInfo>, String> {
15→    let cache = state.session_cache.lock().map_err(|e| e.to_string())?;
16→    let mut sessions = cache.discover_all_project_sessions(&project_dirs)?;
17→    // The session watcher has the most accurate ongoing detection, so apply
18→    // its verdict over the picker's lightweight metadata scan.
19→    state.apply_watched_ongoing(&mut sessions);
20→    Ok(sessions)
21→}
