23→/// Start watching project directories for new/changed sessions.
24→/// Emits "picker-refresh" events.
25→#[tauri::command]
26→pub async fn watch_picker(
27→    project_dirs: Vec<String>,
28→    app: AppHandle,
29→    state: State<'_, AppState>,
30→) -> Result<(), String> {
31→    // Stop existing picker watcher if any.
32→    state.stop_picker_watcher()?;
33→
34→    let handle = start_picker_watcher(project_dirs, app);
35→    state.set_picker_watcher(handle)?;
36→
37→    Ok(())
38→}
