14→pub fn get_git_info(cwd: String) -> GitInfo {
15→    if cwd.is_empty() {
16→        return GitInfo {
17→            branch: String::new(),
18→            dirty: false,
19→            worktree_dirs: Vec::new(),
20→        };
21→    }
22→
23→    let branch = check_git_branch(&cwd);
24→    let dirty = check_git_dirty(&cwd);
25→    let worktree_dirs = discover_worktree_dirs(&cwd);
26→
27→    GitInfo {
28→        branch,
29→        dirty,
30→        worktree_dirs,
31→    }
32→}
33→
34→fn check_git_branch(cwd: &str) -> String {
35→    Command::new("git")
36→        .args(["-C", cwd, "rev-parse", "--abbrev-ref", "HEAD"])
37→        .output()
38→        .ok()
39→        .and_then(|o| {
40→            if o.status.success() {
41→                String::from_utf8(o.stdout)
42→                    .ok()
43→                    .map(|s| s.trim().to_string())
44→            } else {
45→                None
46→            }
47→        })
48→        .unwrap_or_default()
49→}
50→
51→fn check_git_dirty(cwd: &str) -> bool {
52→    Command::new("git")
53→        .args(["-C", cwd, "status", "--porcelain"])
54→        .output()
55→        .ok()
56→        .map(|o| o.status.success() && !o.stdout.is_empty())
57→        .unwrap_or(false)
58→}
59→
60→fn discover_worktree_dirs(cwd: &str) -> Vec<String> {
61→    Command::new("git")
62→        .args(["-C", cwd, "worktree", "list", "--porcelain"])
63→        .output()
64→        .ok()
65→        .and_then(|o| {
66→            if o.status.success() {
67→                String::from_utf8(o.stdout)
68→                    .ok()
69→                    .map(|output| parse_worktree_paths(&output))
70→            } else {
71→                None
72→            }
73→        })
74→        .unwrap_or_default()
75→}
76→
77→fn parse_worktree_paths(output: &str) -> Vec<String> {
78→    output
79→        .lines()
80→        .filter_map(|line| line.strip_prefix("worktree ").map(|p| p.to_string()))
81→        .collect()
82→}
