import { useState, useEffect, useCallback, useRef } from "react";
import { invoke } from "@tauri-apps/api/core";
import type { ViewState, SessionInfo } from "./types";
import { useSession } from "./hooks/useSession";
import { usePicker } from "./hooks/usePicker";
import { useToggleSet } from "./hooks/useToggleSet";
import { useKeyboard } from "./hooks/useKeyboard";
import { SessionPicker } from "./components/SessionPicker";
import { MessageList } from "./components/MessageList";
import { MessageDetail } from "./components/MessageDetail";
import { TeamBoard } from "./components/TeamBoard";
import { DebugViewer } from "./components/DebugViewer";
import { InfoBar } from "./components/InfoBar";
import { KeybindBar } from "./components/KeybindBar";
import { ViewToolbar } from "./components/ViewToolbar";
import { ProjectTree, useProjectKeys } from "./components/ProjectTree";
import { ResizeHandle } from "./components/ResizeHandle";
import { SettingsModal } from "./components/SettingsModal";

export function App() {
  const [view, setView] = useState<ViewState>("picker");
  const [selectedMessage, setSelectedMessage] = useState(0);
  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
  const [showKeybinds, setShowKeybinds] = useState(true);
  const [selectedProject, setSelectedProject] = useState<string | null>(null);
  const [sidebarWidth, setSidebarWidth] = useState(180);
  const [sidebarFocused, setSidebarFocused] = useState(false);
  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
  const [showSettings, setShowSettings] = useState(false);

  const handleSelectProject = useCallback(
    (project: string | null) => {
      setSelectedProject(project);
      setPickerSelectedIndex(0);
      setSidebarFocused(false);
      if (view !== "picker") setView("picker");
    },
    [view],
  );

  const session = useSession();
  const picker = usePicker(selectedProject);
  const projectKeys = useProjectKeys(picker.allSessions);

  const { loadSession, loadDebugLog, sessionPath } = session;
  const { discoverSessions } = picker;

  const {
    set: expandedMessages,
    toggle: toggleMessage,
    clear: clearExpanded,
    addAll: expandMessages,
  } = useToggleSet();

  // Shared: fetch project dirs and discover sessions
  const loadProjectDirs = useCallback(async () => {
    try {
      const dirs = await invoke<string[]>("get_project_dirs");
      if (dirs.length > 0) {
        discoverSessions(dirs);
      }
    } catch (err) {
      console.error("Failed to get project dirs:", err);
    }
  }, [discoverSessions]);

  // Auto-discover sessions on mount; show settings if no path configured
  const discoveredRef = useRef(false);
  useEffect(() => {
    if (discoveredRef.current) return;
    discoveredRef.current = true;
    const discover = async () => {
      let hasConfig = false;
      try {
        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
        hasConfig = settings.projects_dir != null;
      } catch {
        // no settings file yet
      }
      if (!hasConfig) {
        setShowSettings(true);
        return;
      }
      loadProjectDirs();
    };
    discover();
  }, [loadProjectDirs]);

  // Handle session selection from picker
  const handleSelectSession = useCallback(
    (sessionInfo: SessionInfo) => {
      loadSession(sessionInfo.path);
      setView("list");
      setSelectedMessage(0);
      clearExpanded();
    },
    [loadSession, clearExpanded],
  );

  // Auto-select newest message (last index) when messages load
  useEffect(() => {
    if (session.messages.length > 0 && view === "list") {
      setSelectedMessage((prev) =>
        prev >= session.messages.length ? session.messages.length - 1 : prev,
      );
    }
  }, [session.messages.length, view]);

  // Open detail view
  const openDetail = useCallback((index: number) => {
    setSelectedMessage(index);
    setView("detail");
  }, []);

  // -- Extracted action callbacks for toolbar + keyboard --

  const expandAll = useCallback(() => {
    const claudeIndices: number[] = [];
    session.messages.forEach((msg, i) => {
      if (msg.role === "claude") claudeIndices.push(i);
    });
    expandMessages(claudeIndices);
  }, [session.messages, expandMessages]);

  const collapseAll = useCallback(() => {
    clearExpanded();
  }, [clearExpanded]);

  // Visual top = newest message = last index (display is reversed)
  const jumpToTop = useCallback(() => {
    setSelectedMessage(Math.max(session.messages.length - 1, 0));
  }, [session.messages.length]);

  // Visual bottom = oldest message = index 0
  const jumpToBottom = useCallback(() => {
    setSelectedMessage(0);
  }, []);

  const openDebug = useCallback(() => {
    if (sessionPath) {
      loadDebugLog(sessionPath);
      setView("debug");
    }
  }, [sessionPath, loadDebugLog]);

  const openTeams = useCallback(() => {
    if (session.teams.length > 0) setView("team");
  }, [session.teams.length]);

  const goToSessions = useCallback(() => {
    setView("picker");
  }, []);

  const backToList = useCallback(() => {
    if (sessionPath) setView("list");
  }, [sessionPath]);

  const toggleKeybinds = useCallback(() => {
    setShowKeybinds((v) => !v);
  }, []);

  const selectProjectByIndex = useCallback(
    (index: number) => {
      if (index >= 0 && index < projectKeys.length) {
        handleSelectProject(projectKeys[index]);
      }
    },
    [projectKeys, handleSelectProject],
  );

  // Keyboard navigation — build keyMap per view
  const keyMap: Record<string, () => void> = {};

  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
  if (sidebarFocused) {
    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
    keyMap["j"] = sidebarDown;
    keyMap["ArrowDown"] = sidebarDown;
    keyMap["k"] = sidebarUp;
    keyMap["ArrowUp"] = sidebarUp;
    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
    keyMap["Escape"] = () => setSidebarFocused(false);
    keyMap["l"] = () => setSidebarFocused(false);
    keyMap["ArrowRight"] = () => setSidebarFocused(false);
    keyMap["?"] = toggleKeybinds;
  } else {
    switch (view) {
      case "list": {
        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
        const listUp = () =>
          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
        keyMap["j"] = listDown;
        keyMap["ArrowDown"] = listDown;
        keyMap["k"] = listUp;
        keyMap["ArrowUp"] = listUp;
        keyMap["G"] = jumpToTop;
        keyMap["g"] = jumpToBottom;
        keyMap["Tab"] = () => toggleMessage(selectedMessage);
        keyMap["Enter"] = () => {
          if (session.messages.length > 0) openDetail(selectedMessage);
        };
        keyMap["e"] = expandAll;
        keyMap["c"] = collapseAll;
        keyMap["t"] = openTeams;
        keyMap["d"] = openDebug;
        keyMap["q"] = goToSessions;
        keyMap["Escape"] = goToSessions;
        keyMap["s"] = goToSessions;
        keyMap["?"] = toggleKeybinds;
        keyMap["h"] = () => setSidebarFocused(true);
        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
        break;
      }
      case "detail":
        // j/k/Tab/Enter/q/Escape handled by MessageDetail's own useKeyboard
        keyMap["?"] = toggleKeybinds;
        break;
      case "picker": {
        const pickerDown = () =>
          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
        keyMap["j"] = pickerDown;
        keyMap["ArrowDown"] = pickerDown;
        keyMap["k"] = pickerUp;
        keyMap["ArrowUp"] = pickerUp;
        keyMap["Enter"] = () => {
          if (picker.sessions[pickerSelectedIndex])
            handleSelectSession(picker.sessions[pickerSelectedIndex]);
        };
        keyMap["q"] = backToList;
        keyMap["Escape"] = backToList;
        keyMap["?"] = toggleKeybinds;
        keyMap["h"] = () => setSidebarFocused(true);
        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
        break;
      }
      case "team":
        keyMap["q"] = () => setView("list");
        keyMap["Escape"] = () => setView("list");
        keyMap["?"] = toggleKeybinds;
        break;
      case "debug":
        keyMap["q"] = () => setView("list");
        keyMap["Escape"] = () => setView("list");
        keyMap["?"] = toggleKeybinds;
        break;
    }
  }
  useKeyboard(keyMap);

  // Keybind bar click actions
  const keybindActions: Record<string, () => void> = {};
  if (view === "list") {
    keybindActions["debug"] = openDebug;
    keybindActions["sessions"] = goToSessions;
    if (session.teams.length > 0) {
      keybindActions["tasks"] = openTeams;
    }
  } else if (view === "picker") {
    keybindActions["back"] = backToList;
  } else if (view === "detail") {
    keybindActions["back"] = () => setView("list");
  } else if (view === "team") {
    keybindActions["back"] = () => setView("list");
  } else if (view === "debug") {
    keybindActions["back"] = () => setView("list");
  }

  // Render the active view
  const renderView = () => {
    switch (view) {
      case "picker":
        return (
          <SessionPicker
            sessions={picker.sessions}
            loading={picker.loading}
            searchQuery={picker.searchQuery}
            selectedIndex={pickerSelectedIndex}
            onSelect={handleSelectSession}
            onSearchChange={picker.setSearchQuery}
            onSelectIndex={setPickerSelectedIndex}
          />
        );

      case "list":
        return (
          <MessageList
            messages={session.messages}
            selectedIndex={selectedMessage}
            expandedSet={expandedMessages}
            ongoing={session.ongoing}
            onSelect={setSelectedMessage}
            onToggle={toggleMessage}
            onOpenDetail={openDetail}
          />
        );

      case "detail":
        if (session.messages.length > 0 && selectedMessage < session.messages.length) {
          return (
            <MessageDetail
              message={session.messages[selectedMessage]}
              ongoing={session.ongoing}
              onBack={() => setView("list")}
            />
          );
        }
        return null;

      case "team":
        return <TeamBoard teams={session.teams} onBack={() => setView("list")} />;

      case "debug":
        return <DebugViewer entries={session.debugEntries} onBack={() => setView("list")} />;
    }
  };

  return (
    <div className="app">
      {/* Info bar — only show when we have a loaded session */}
      {session.sessionPath && view !== "picker" && (
        <InfoBar
          meta={session.meta}
          gitInfo={session.gitInfo}
          messages={session.messages}
          sessionTotals={session.sessionTotals}
          sessionPath={session.sessionPath}
          ongoing={session.ongoing}
        />
      )}

      {/* View toolbar */}
      <ViewToolbar
        view={view}
        hasTeams={session.teams.length > 0}
        hasSession={!!session.sessionPath}
        messageCount={session.messages.length}
        onGoToSessions={goToSessions}
        onExpandAll={expandAll}
        onCollapseAll={collapseAll}
        onJumpTop={jumpToTop}
        onJumpBottom={jumpToBottom}
        onOpenTeams={openTeams}
        onOpenDebug={openDebug}
        onBackToList={backToList}
        onOpenSettings={() => setShowSettings(true)}
      />

      <div className="app-body">
        <ProjectTree
          sessions={picker.allSessions}
          selectedProject={selectedProject}
          highlightedIndex={sidebarHighlight}
          isFocused={sidebarFocused}
          onSelectProject={handleSelectProject}
          onRefresh={loadProjectDirs}
          onFocus={() => setSidebarFocused(true)}
          refreshing={picker.loading}
          style={{ width: sidebarWidth, minWidth: 100, maxWidth: 400 }}
        />
        <ResizeHandle onResize={setSidebarWidth} />
        <div className="main-content" onClick={() => setSidebarFocused(false)}>
          {renderView()}
        </div>
      </div>

      {/* Keybind bar */}
      <KeybindBar
        view={view}
        hasTeams={session.teams.length > 0}
        showHints={showKeybinds}
        onToggle={toggleKeybinds}
        actions={keybindActions}
      />

      {showSettings && (
        <SettingsModal onClose={() => setShowSettings(false)} onSaved={loadProjectDirs} />
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import { PopoutModal } from "./PopoutModal";

interface SettingsResponse {
  projects_dir: string | null;
  default_dir: string;
}

interface SettingsModalProps {
  onClose: () => void;
  onSaved: () => void;
}

export function SettingsModal({ onClose, onSaved }: SettingsModalProps) {
  const [projectsDir, setProjectsDir] = useState("");
  const [defaultDir, setDefaultDir] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    invoke<SettingsResponse>("get_settings")
      .then((res) => {
        setDefaultDir(res.default_dir);
        setProjectsDir(res.projects_dir ?? res.default_dir);
      })
      .catch((err) => {
        console.error("Failed to load settings:", err);
      });
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    setError("");
    try {
      await invoke<SettingsResponse>("set_projects_dir", { path: projectsDir.trim() || null });
      onSaved();
      onClose();
    } catch (err) {
      setError(String(err));
    } finally {
      setSaving(false);
    }
  }, [projectsDir, onSaved, onClose]);

  const handleReset = useCallback(async () => {
    setSaving(true);
    setError("");
    try {
      const res = await invoke<SettingsResponse>("set_projects_dir", { path: null });
      setProjectsDir(res.default_dir);
      onSaved();
      onClose();
    } catch (err) {
      setError(String(err));
    } finally {
      setSaving(false);
    }
  }, [onSaved, onClose]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter") {
        e.preventDefault();
        handleSave();
      }
    },
    [handleSave],
  );

  return (
    <PopoutModal
      onClose={onClose}
      header={<span className="settings-modal__title">Settings</span>}
      initialWidth={520}
      initialHeight={240}
    >
      <div className="settings-modal">
        <label className="settings-modal__label" htmlFor="projects-dir">
          Projects Directory
        </label>
        <input
          id="projects-dir"
          className="settings-modal__input"
          type="text"
          value={projectsDir}
          onChange={(e) => {
            setProjectsDir(e.target.value);
            setError("");
          }}
          onKeyDown={handleKeyDown}
          placeholder={defaultDir}
          spellCheck={false}
          autoFocus
        />
        <p className="settings-modal__hint">Default: {defaultDir}</p>
        {error && <p className="settings-modal__error">{error}</p>}
        <div className="settings-modal__actions">
          <button
            className="settings-modal__btn settings-modal__btn--secondary"
            onClick={handleReset}
            disabled={saving}
          >
            Reset to Default
          </button>
          <button
            className="settings-modal__btn settings-modal__btn--primary"
            onClick={handleSave}
            disabled={saving}
          >
            Save
          </button>
        </div>
      </div>
    </PopoutModal>
  );
}

import { useState, useEffect, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import type {
  DisplayMessage,
  TeamSnapshot,
  SessionMeta,
  SessionTotals,
  LoadResult,
  GitInfo,
  DebugEntry,
} from "../types";
import { useTauriEvent } from "./useTauriEvent";

interface SessionState {
  messages: DisplayMessage[];
  teams: TeamSnapshot[];
  ongoing: boolean;
  meta: SessionMeta;
  sessionTotals: SessionTotals;
  sessionPath: string;
  gitInfo: GitInfo | null;
  debugEntries: DebugEntry[];
  loading: boolean;
}

const emptyMeta: SessionMeta = {
  cwd: "",
  git_branch: "",
  permission_mode: "",
};

const emptyTotals: SessionTotals = {
  total_tokens: 0,
  input_tokens: 0,
  output_tokens: 0,
  cache_read_tokens: 0,
  cache_creation_tokens: 0,
  cost_usd: 0,
  model: "",
};

export function useSession() {
  const [state, setState] = useState<SessionState>({
    messages: [],
    teams: [],
    ongoing: false,
    meta: emptyMeta,
    sessionTotals: emptyTotals,
    sessionPath: "",
    gitInfo: null,
    debugEntries: [],
    loading: false,
  });

  const loadSession = useCallback(async (path: string) => {
    setState((prev) => ({ ...prev, loading: true }));
    try {
      // Stop watching previous session
      try {
        await invoke<void>("unwatch_session");
      } catch {
        // ignore if no session was being watched
      }

      const result = await invoke<LoadResult>("load_session", { path });

      // Extract git info from session cwd
      let gitInfo: GitInfo | null = null;
      if (result.meta.cwd) {
        try {
          gitInfo = await invoke<GitInfo>("get_git_info", {
            cwd: result.meta.cwd,
          });
        } catch {
          // git info is optional
        }
      }

      setState({
        messages: result.messages,
        teams: result.teams,
        ongoing: result.ongoing,
        meta: result.meta,
        sessionTotals: result.session_totals,
        sessionPath: path,
        gitInfo,
        debugEntries: [],
        loading: false,
      });

      // Start watching for updates
      try {
        await invoke<void>("watch_session", { path });
      } catch {
        // watcher is optional
      }
    } catch (err) {
      console.error("Failed to load session:", err);
      setState((prev) => ({ ...prev, loading: false }));
    }
  }, []);

  const loadDebugLog = useCallback(async (sessionPath: string) => {
    try {
      const entries = await invoke<DebugEntry[]>("get_debug_log", {
        sessionPath,
      });
      setState((prev) => ({ ...prev, debugEntries: entries }));
    } catch (err) {
      console.error("Failed to load debug log:", err);
    }
  }, []);

  // Listen for session-update events
  useTauriEvent<{
    messages: DisplayMessage[];
    teams: TeamSnapshot[];
    ongoing: boolean;
    permission_mode: string;
    session_totals: SessionTotals;
  }>("session-update", (payload) => {
    setState((prev) => ({
      ...prev,
      messages: payload.messages,
      teams: payload.teams,
      ongoing: payload.ongoing,
      sessionTotals: payload.session_totals,
      meta: {
        ...prev.meta,
        permission_mode: payload.permission_mode || prev.meta.permission_mode,
      },
    }));
  });

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      invoke<void>("unwatch_session").catch(() => {});
    };
  }, []);

  return {
    ...state,
    loadSession,
    loadDebugLog,
  };
}

import { useState, useEffect, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import type { SessionInfo } from "../types";
import { useTauriEvent } from "./useTauriEvent";

interface PickerState {
  sessions: SessionInfo[];
  loading: boolean;
  searchQuery: string;
}

export function usePicker(selectedProject: string | null = null) {
  const [state, setState] = useState<PickerState>({
    sessions: [],
    loading: false,
    searchQuery: "",
  });

  const discoverSessions = useCallback(async (projectDirs: string[]) => {
    setState((prev) => ({ ...prev, loading: true }));
    try {
      const sessions = await invoke<SessionInfo[]>("discover_sessions", {
        projectDirs,
      });
      setState((prev) => ({ ...prev, sessions, loading: false }));

      // Start watching for new sessions
      try {
        await invoke<void>("watch_picker", { projectDirs });
      } catch {
        // watcher is optional
      }
    } catch (err) {
      console.error("Failed to discover sessions:", err);
      setState((prev) => ({ ...prev, loading: false }));
    }
  }, []);

  const setSearchQuery = useCallback((query: string) => {
    setState((prev) => ({ ...prev, searchQuery: query }));
  }, []);

  // Listen for picker-refresh events (backend already applies staleness)
  useTauriEvent<{ sessions: SessionInfo[] }>("picker-refresh", (payload) => {
    setState((prev) => ({
      ...prev,
      sessions: payload.sessions,
    }));
  });

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      invoke<void>("unwatch_picker").catch(() => {});
    };
  }, []);

  // Filter sessions by search query
  let filteredSessions = state.searchQuery
    ? state.sessions.filter(
        (s) =>
          s.first_message.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
          s.session_id.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
          s.model.toLowerCase().includes(state.searchQuery.toLowerCase()),
      )
    : state.sessions;

  // Filter by selected project
  if (selectedProject) {
    filteredSessions = filteredSessions.filter((s) =>
      s.path.replace(/\\/g, "/").includes(`/.claude/projects/${selectedProject}/`),
    );
  }

  return {
    sessions: filteredSessions,
    allSessions: state.sessions,
    loading: state.loading,
    searchQuery: state.searchQuery,
    setSearchQuery,
    discoverSessions,
  };
}

import { useEffect, useRef } from "react";
import { listen, type UnlistenFn } from "@tauri-apps/api/event";

/**
 * Subscribe to a Tauri event with automatic setup/teardown and cancellation safety.
 * The handler is kept in a ref so it always sees fresh closures without re-subscribing.
 */
export function useTauriEvent<T>(event: string, handler: (payload: T) => void) {
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  const unlistenRef = useRef<UnlistenFn | null>(null);

  useEffect(() => {
    let cancelled = false;

    const setupListener = async () => {
      const unlisten = await listen<T>(event, (e) => {
        if (!cancelled) handlerRef.current(e.payload);
      });

      if (!cancelled) {
        unlistenRef.current = unlisten;
      } else {
        unlisten();
      }
    };

    setupListener();

    return () => {
      cancelled = true;
      unlistenRef.current?.();
      unlistenRef.current = null;
    };
  }, [event]);
}

