/**
 * Safe wrapper around Tauri's `listen`.
 *
 * In the Tauri webview it delegates to the real event system.
 * In a plain browser it returns a no-op unlisten function.
 */
import { listen as tauriListen } from "@tauri-apps/api/event";
import { isTauri } from "./isTauri";

type UnlistenFn = () => void;

export async function listen<T>(
  event: string,
  handler: (event: { payload: T }) => void,
): Promise<UnlistenFn> {
  if (isTauri) {
    return tauriListen<T>(event, handler);
  }
  // In browser mode, events never fire — return a no-op cleanup
  return () => {};
}

import { useEffect, useRef } from "react";
import { listen } from "../lib/listen";

/**
 * Subscribe to a Tauri event with automatic setup/teardown and cancellation safety.
 * The handler is kept in a ref so it always sees fresh closures without re-subscribing.
 */
export function useTauriEvent<T>(event: string, handler: (payload: T) => void) {
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  const unlistenRef = useRef<(() => void) | null>(null);

  useEffect(() => {
    let cancelled = false;

    const setupListener = async () => {
      const unlisten = await listen<T>(event, (e) => {
        if (!cancelled) handlerRef.current(e.payload);
      });

      if (!cancelled) {
        unlistenRef.current = unlisten;
      } else {
        unlisten();
      }
    };

    setupListener();

    return () => {
      cancelled = true;
      unlistenRef.current?.();
      unlistenRef.current = null;
    };
  }, [event]);
}

