 3→use crate::parser::cache::SessionCache;
 4→use crate::settings::Settings;
 5→use crate::watcher::WatcherHandle;
 6→
 7→/// AppState holds shared state managed by Tauri.
 8→pub struct AppState {
 9→    pub session_watcher: Mutex<Option<WatcherHandle>>,
10→    pub picker_watcher: Mutex<Option<WatcherHandle>>,
11→    pub session_cache: Mutex<SessionCache>,
12→    pub settings: Mutex<Settings>,
13→    /// Ongoing status reported by the session watcher for the currently viewed session.
14→    /// (session_path, is_ongoing) — kept in sync by the session watcher loop.
15→    pub watched_session_ongoing: Mutex<Option<(String, bool)>>,
16→}
17→
18→impl AppState {
19→    pub fn new() -> Self {
20→        Self {
21→            session_watcher: Mutex::new(None),
22→            picker_watcher: Mutex::new(None),
23→            session_cache: Mutex::new(SessionCache::new()),
24→            settings: Mutex::new(crate::settings::load_settings()),
25→            watched_session_ongoing: Mutex::new(None),
26→        }
27→    }
28→
29→    /// Stop and clear the session watcher if one is running.
30→    pub fn stop_session_watcher(&self) -> Result<(), String> {
31→        let mut guard = self.session_watcher.lock().map_err(|e| e.to_string())?;
32→        if let Some(handle) = guard.take() {
33→            handle.stop();
34→        }
35→        Ok(())
36→    }
37→
38→    /// Replace the session watcher with a new handle.
39→    pub fn set_session_watcher(&self, handle: WatcherHandle) -> Result<(), String> {
40→        let mut guard = self.session_watcher.lock().map_err(|e| e.to_string())?;
41→        *guard = Some(handle);
42→        Ok(())
43→    }
44→
45→    /// Stop and clear the picker watcher if one is running.
46→    pub fn stop_picker_watcher(&self) -> Result<(), String> {
47→        let mut guard = self.picker_watcher.lock().map_err(|e| e.to_string())?;
48→        if let Some(handle) = guard.take() {
49→            handle.stop();
50→        }
51→        Ok(())
52→    }
53→
54→    /// Replace the picker watcher with a new handle.
55→    pub fn set_picker_watcher(&self, handle: WatcherHandle) -> Result<(), String> {
56→        let mut guard = self.picker_watcher.lock().map_err(|e| e.to_string())?;
57→        *guard = Some(handle);
58→        Ok(())
59→    }
60→
61→    /// Update the ongoing status for the currently watched session.
62→    pub fn set_watched_ongoing(&self, path: String, ongoing: bool) {
63→        if let Ok(mut guard) = self.watched_session_ongoing.lock() {
64→            *guard = Some((path, ongoing));
65→        }
66→    }
67→
68→    /// Clear the watched session ongoing status (e.g. when unwatching).
69→    pub fn clear_watched_ongoing(&self) {
70→        if let Ok(mut guard) = self.watched_session_ongoing.lock() {
71→            *guard = None;
72→        }
73→    }
74→
75→    /// Apply the session watcher's ongoing status to a list of sessions.
76→    /// The session watcher has the most accurate ongoing detection (full chunk
77→    /// analysis + subagent tracking), so its verdict overrides the picker's
78→    /// lightweight metadata scan.
79→    pub fn apply_watched_ongoing(&self, sessions: &mut [crate::parser::session::SessionInfo]) {
80→        let guard = match self.watched_session_ongoing.lock() {
81→            Ok(g) => g,
82→            Err(_) => return,
83→        };
84→        if let Some((ref path, ongoing)) = *guard {
85→            if let Some(s) = sessions.iter_mut().find(|s| s.path == *path) {
86→                s.is_ongoing = ongoing;
87→            }
88→        }
89→    }
90→}
