 1→use crate::parser::debuglog::*;
 2→
 3→/// Get debug log entries for a session, with optional filtering.
 4→#[tauri::command]
 5→pub async fn get_debug_log(
 6→    session_path: String,
 7→    min_level: Option<String>,
 8→    filter_text: Option<String>,
 9→) -> Result<Vec<DebugEntry>, String> {
10→    let debug_path = debug_log_path(&session_path);
11→    if debug_path.is_empty() {
12→        return Ok(Vec::new());
13→    }
14→
15→    let (entries, _offset) = read_debug_log(&debug_path)?;
16→
17→    let level = match min_level.as_deref() {
18→        Some("WARN") | Some("warn") => DebugLevel::Warn,
19→        Some("ERROR") | Some("error") => DebugLevel::Error,
20→        _ => DebugLevel::Debug,
21→    };
22→
23→    let filtered = filter_by_level(&entries, &level);
24→    let filtered = filter_by_text(&filtered, filter_text.as_deref().unwrap_or(""));
25→    let collapsed = collapse_duplicates(filtered);
26→
27→    Ok(collapsed)
28→}
