 68→/// Start watching a session file. Emits "session-update" events on changes.
 69→pub fn start_session_watcher(
 70→    path: String,
 71→    initial_classified: Vec<ClassifiedMsg>,
 72→    initial_offset: u64,
 73→    app: AppHandle,
 74→) -> WatcherHandle {
 75→    let (stop_tx, mut stop_rx) = mpsc::channel::<()>(1);
 76→    let (signal_tx, mut signal_rx) = mpsc::channel::<()>(4);
 77→
 78→    let path_clone = path.clone();
 79→    let signal_tx_clone = signal_tx.clone();
 80→
 81→    // Spawn the file watcher thread (notify requires std thread).
 82→    std::thread::spawn(move || {
 83→        let signal_tx = signal_tx_clone;
 84→        let path = path_clone;
 85→
 86→        let (tx, rx) = std::sync::mpsc::channel();
 87→        let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
 88→            Ok(w) => w,
 89→            Err(_) => return,
 90→        };
 91→
 92→        // Watch the project directory recursively — catches the session file,
 93→        // team session files, and subagent files in any subdirectory (including
 94→        // subagent directories created after the watcher starts).
 95→        let project_dir = Path::new(&path).parent().unwrap_or(Path::new(""));
 96→        let _ = watcher.watch(project_dir, RecursiveMode::Recursive);
 97→
 98→        // Only react to changes in this session's files — not other sessions.
 99→        let session_file = path.clone();
100→        let session_base = Path::new(&path)
101→            .file_stem()
102→            .and_then(|s| s.to_str())
103→            .unwrap_or("")
104→            .to_string();
105→        let project_dir_str = project_dir.to_string_lossy().to_string();
106→
107→        run_debounce_loop(
108→            rx,
109→            move |event| {
110→                event.paths.iter().any(|p| {
111→                    let ps = p.to_string_lossy();
112→                    // Exact match on the session file.
113→                    if ps == session_file {
114→                        return true;
115→                    }
116→                    // Files inside this session's subdirectory (subagents, etc.).
117→                    if let Some(parent) = p.parent() {
118→                        let parent_str = parent.to_string_lossy();
119→                        if parent_str.contains(&session_base) {
120→                            return p.extension().map(|e| e == "jsonl").unwrap_or(false);
121→                        }
122→                    }
123→                    // New team session files directly in the project directory.
124→                    if let Some(parent) = p.parent() {
125→                        if parent.to_string_lossy() == project_dir_str {
126→                            return p.extension().map(|e| e == "jsonl").unwrap_or(false);
127→                        }
128→                    }
129→                    false
130→                })
131→            },
132→            signal_tx,
133→        );
134→    });
135→
136→    // Spawn the async rebuild loop.
137→    let path_for_rebuild = path.clone();
138→    tauri::async_runtime::spawn(async move {
139→        let mut all_classified = initial_classified;
140→        let mut offset = initial_offset;
141→        let mut token_scanner = IncrementalTokenScanner::new();
142→        let mut prev_msg_count: usize = 0;
143→        let mut prev_ongoing = false;
144→
145→        // Seed the token scanner with the initial file content.
146→        token_scanner.scan_new_bytes(&path_for_rebuild);
147→
148→        loop {
149→            tokio::select! {
150→                _ = stop_rx.recv() => {
151→                    break;
152→                }
153→                Some(()) = signal_rx.recv() => {
154→                    // Read any new data from the main session file.
155→                    match read_session_incremental(&path_for_rebuild, offset) {
156→                        Ok((new_msgs, new_offset, _)) => {
157→                            if !new_msgs.is_empty() || new_offset != offset {
158→                                offset = new_offset;
159→                                all_classified.extend(new_msgs);
160→                            }
161→                        }
162→                        Err(_) => continue,
163→                    }
164→
165→                    let mut chunks = build_chunks(&all_classified);
166→
167→                    let (mut all_procs, color_map) = discover_and_link_all(&path_for_rebuild, &chunks);
168→                    inject_orphan_subagents(&mut chunks, &mut all_procs);
169→
170→                    let ongoing = OngoingChecker::new(&chunks, &all_procs, &path_for_rebuild).is_ongoing();
171→
172→                    // Share ongoing status with AppState so the picker can use it.
173→                    if let Some(state) = app.try_state::<crate::state::AppState>() {
174→                        state.set_watched_ongoing(path_for_rebuild.clone(), ongoing);
175→                    }
176→
177→                    let teams = reconstruct_teams(&chunks, &all_procs);
178→                    let messages = chunks_to_messages(&chunks, &all_procs, &color_map);
179→
180→                    // Skip emit if nothing meaningful changed.
181→                    let msg_count = messages.len();
182→                    if msg_count == prev_msg_count && !ongoing && !prev_ongoing {
183→                        // Token totals may still have changed — update scanner
184→                        // but skip the expensive emit + serialize.
185→                        token_scanner.scan_new_bytes(&path_for_rebuild);
186→                        continue;
187→                    }
188→                    prev_msg_count = msg_count;
189→                    prev_ongoing = ongoing;
190→
191→                    // Extract last permission_mode from UserMsg entries.
192→                    let mut permission_mode = String::from("default");
193→                    for msg in all_classified.iter().rev() {
194→                        if let ClassifiedMsg::User(u) = msg {
195→                            if !u.permission_mode.is_empty() {
196→                                permission_mode = u.permission_mode.clone();
197→                                break;
198→                            }
199→                        }
200→                    }
201→
202→                    // Incrementally scan only new bytes for token totals.
203→                    let session_totals = token_scanner.scan_new_bytes(&path_for_rebuild);
204→
205→                    let payload = SessionUpdatePayload {
206→                        messages,
207→                        teams,
208→                        ongoing,
209→                        permission_mode,
210→                        session_totals,
211→                    };
212→
213→                    let _ = app.emit("session-update", payload);
214→                }
215→            }
216→        }
217→    });
218→
219→    WatcherHandle { stop_tx }
220→}
