/**
 * Safe wrapper around Tauri's `invoke`.
 *
 * In the Tauri webview it delegates to the real IPC bridge.
 * In a plain browser it calls the Rust backend's HTTP API on port 11423.
 */
import { invoke as tauriInvoke } from "@tauri-apps/api/core";
import { isTauri } from "./isTauri";

const API_BASE = "http://127.0.0.1:11423";

/** Map Tauri command names to HTTP API calls. */
async function httpInvoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
  switch (cmd) {
    case "get_settings":
      return fetchJson(`${API_BASE}/api/settings`);
    case "set_projects_dir":
      return fetchJson(`${API_BASE}/api/settings/dir`, {
        method: "POST",
        body: JSON.stringify({ path: args?.path ?? null }),
      });
    case "get_project_dirs":
      return fetchJson(`${API_BASE}/api/project-dirs`);
    case "discover_sessions": {
      const dirs = (args?.projectDirs as string[]) ?? [];
      return fetchJson(`${API_BASE}/api/sessions?dirs=${encodeURIComponent(dirs.join(","))}`);
    }
    case "load_session":
      return fetchJson(`${API_BASE}/api/session/load`, {
        method: "POST",
        body: JSON.stringify({ path: args?.path }),
      });
    case "get_session_meta":
      return fetchJson(`${API_BASE}/api/session/meta?path=${encodeURIComponent(String(args?.path ?? ""))}`);
    case "watch_session":
      return fetchJson(`${API_BASE}/api/session/watch`, {
        method: "POST",
        body: JSON.stringify({ path: args?.path }),
      });
    case "unwatch_session":
      return fetchJson(`${API_BASE}/api/session/unwatch`, { method: "POST" });
    case "watch_picker":
      return fetchJson(`${API_BASE}/api/picker/watch`, {
        method: "POST",
        body: JSON.stringify({ projectDirs: args?.projectDirs }),
      });
    case "unwatch_picker":
      return fetchJson(`${API_BASE}/api/picker/unwatch`, { method: "POST" });
    case "get_git_info":
      return fetchJson(`${API_BASE}/api/git-info?cwd=${encodeURIComponent(String(args?.cwd ?? ""))}`);
    case "get_debug_log": {
      const params = new URLSearchParams();
      params.set("path", String(args?.sessionPath ?? ""));
      if (args?.minLevel) params.set("minLevel", String(args.minLevel));
      if (args?.filterText) params.set("filterText", String(args.filterText));
      return fetchJson(`${API_BASE}/api/debug-log?${params}`);
    }
    default:
      throw new Error(`[web] Unknown command "${cmd}"`);
  }
}

async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
  const res = await fetch(url, {
    ...init,
    headers: { "Content-Type": "application/json", ...init?.headers },
  });
  if (!res.ok) {
    const body = await res.json().catch(() => ({ error: res.statusText }));
    throw new Error(body.error ?? res.statusText);
  }
  // Some endpoints return 200 with no meaningful body (watch/unwatch).
  const text = await res.text();
  return text ? (JSON.parse(text) as T) : (undefined as T);
}

/**
 * Drop-in replacement for `import { invoke } from "@tauri-apps/api/core"`.
 * Works in both Tauri and plain-browser environments.
 */
export async function invoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
  if (isTauri) {
    return tauriInvoke<T>(cmd, args);
  }
  return httpInvoke<T>(cmd, args);
}

